/* Pack the IDoc payload from up to 4 (facet_id, data, len) tuples into
 * out_payload_ptr[0..out_cap). Returns bytes written, or IDOC_PACK_OVERFLOW
 * (0xFFFFFFFF) if any facet would exceed out_cap or carries a null data ptr.
 *
 * Overflow-safe capacity check: `len_p > out_cap - total_off - 5u32` uses
 * subtraction to avoid u32 addition wrap (invariant: total_off + 5 <= out_cap
 * is proven by each prior iteration's successful check). */
fn idoc_pack_payload(facet_ids_ptr: u64, facet_data_ptrs_ptr: u64, facet_lens_ptr: u64, out_payload_ptr: u64, out_cap: u32) -> u32 @export {
    let fids_l : u64 = facet_ids_ptr
    let fdps_l : u64 = facet_data_ptrs_ptr
    let flns_l : u64 = facet_lens_ptr
    let out_l  : u64 = out_payload_ptr
    let cap_l  : u32 = out_cap
    if fids_l == 0u64 { return IDOC_PACK_OVERFLOW }
    if fdps_l == 0u64 { return IDOC_PACK_OVERFLOW }
    if flns_l == 0u64 { return IDOC_PACK_OVERFLOW }
    if out_l  == 0u64 { return IDOC_PACK_OVERFLOW }
    /* Reads:
     *   facet_ids[i] : u8
     *   facet_data_ptrs[i] : u64
     *   facet_lens[i] : u32
     * for i in 0..4. Skip facets with len == 0. */
    let mut total_off : u32 = 0u32
    let mut i : u32 = 0u32
    while i < 4u32 {
        let id_p   : *u8  = (fids_l + ((i as u64) & 0xFFu64)) as *u8
        let dpa    : u64 = fdps_l + ((i as u64) & 0xFFu64) * 8u64
        let dp_pp  : *u64 = dpa as *u64
        let len_p  : u32  = _idoc_read_u32_le(flns_l, ((i as u64) & 0xFFu64) * 4u64)
        let dp_v   : u64  = dp_pp[0u64]
        if len_p > 0u32 {
            /* Null facet data pointer: reject the whole pack. */
            if dp_v == 0u64 { return IDOC_PACK_OVERFLOW }
            /* Overflow-safe capacity check: need 5 + len_p bytes at total_off.
             * Subtraction form: reject if len_p > cap_l - total_off - 5u32.
             * Guard: cap_l - total_off < 5u32 also catches the 5-byte header
             * overflow independently (since len_p >= 0). */
            if cap_l < total_off + 5u32 { return IDOC_PACK_OVERFLOW }
            if len_p > cap_l - total_off - 5u32 { return IDOC_PACK_OVERFLOW }
            /* Write 1-byte facet_id. */
            let header_bp : *u8 = (out_l + (total_off as u64)) as *u8
            header_bp[0u64] = id_p[0u64]
            /* Write 4-byte LE facet_len. */
            _idoc_write_u32_le(out_l, (total_off as u64) + 1u64, len_p)
            /* Copy facet bytes. */
            let mut j : u32 = 0u32
            while j < len_p {
                let src : *u8 = (dp_v + ((j as u64) & 0xFFFFFFFFu64)) as *u8
                let dst : *u8 = (out_l + (total_off as u64) + 5u64 + ((j as u64) & 0xFFFFFFFFu64)) as *u8
                dst[0u64] = src[0u64]
                j = j + 1u32
            }
            total_off = total_off + 5u32 + len_p
        }
        i = i + 1u32
    }
    return total_off
}

