/* C:\Users\Edwin Boston\OneDrive\Desktop\III\STDLIB\corpus\420_idoc_pack_outcap.iii
 *
 * III conformance corpus 420 -- idoc_pack_payload: out-capacity + null-facet-ptr guards.
 *
 * Asserts (negative cases, proving the fix fires):
 *   1. out_cap too small for first facet header (5 bytes) -> returns IDOC_PACK_OVERFLOW.
 *   2. out_cap exact for first facet but too small for second -> returns OVERFLOW.
 *   3. Null data pointer for a non-zero-len facet -> returns IDOC_PACK_OVERFLOW.
 *   4. out_cap zero, non-zero len -> returns IDOC_PACK_OVERFLOW.
 *   5. out_payload_ptr null -> returns IDOC_PACK_OVERFLOW.
 *   6. facet_ids_ptr null -> returns IDOC_PACK_OVERFLOW.
 *
 * Positive cases (proving the fix does NOT over-reject):
 *   7. Exact-fit pack: out_cap == sum of all facet records -> returns exact byte count.
 *   8. Single facet with out_cap = 5 + len -> returns 5 + len.
 *   9. All-zero lens (no facets written) -> returns 0.
 *
 * Exit code: 99 on full pass; 1..N on specific failure.
 */

module corpus_420

extern @abi(c-msvc-x64) fn malloc(n: u64) -> *u8 from "msvcrt"
extern @abi(c-msvc-x64) fn free(p: *u8) -> u64 from "msvcrt"

extern @abi(c-msvc-x64) fn idoc_pack_payload(facet_ids_ptr: u64, facet_data_ptrs_ptr: u64, facet_lens_ptr: u64, out_payload_ptr: u64, out_cap: u32) -> u32 from "idoc.iii"

const OVERFLOW_SENTINEL : u32 = 0xFFFFFFFFu32

/* Helper: write u64 LE byte-wise into buf at byte offset off. */
fn _w64(buf: *u8, off: u64, v: u64) -> i32 {
    let mut i : u64 = 0u64
    while i < 8u64 {
        buf[off + i] = ((v >> (i * 8u64)) & 0xFFu64) as u8
        i = i + 1u64
    }
    return 0i32
}

/* Helper: write u32 LE byte-wise. */
fn _w32(buf: *u8, off: u64, v: u32) -> i32 {
    buf[off]            = (v & 0xFFu32) as u8
    buf[off + 1u64]     = ((v >> 8u32)  & 0xFFu32) as u8
    buf[off + 2u64]     = ((v >> 16u32) & 0xFFu32) as u8
    buf[off + 3u64]     = ((v >> 24u32) & 0xFFu32) as u8
    return 0i32
}

fn main() -> u64 {
    /* Working buffers. */
    let data_a : *u8 = malloc(8u64)    /* 8 bytes of facet data, facet 0 */
    let data_b : *u8 = malloc(4u64)    /* 4 bytes of facet data, facet 1 */
    let out    : *u8 = malloc(256u64)  /* output region */
    let fids   : *u8 = malloc(4u64)    /* facet_ids[4] */
    let fdpa   : *u8 = malloc(32u64)   /* facet_data_ptrs[4] (u64 each) */
    let flna   : *u8 = malloc(16u64)   /* facet_lens[4] (u32 each) */
    if data_a as u64 == 0u64 { return 1u64 }
    if data_b as u64 == 0u64 { return 1u64 }
    if out    as u64 == 0u64 { return 1u64 }
    if fids   as u64 == 0u64 { return 1u64 }
    if fdpa   as u64 == 0u64 { return 1u64 }
    if flna   as u64 == 0u64 { return 1u64 }

    /* Fill data buffers with recognisable bytes. */
    let mut ii : u64 = 0u64
    while ii < 8u64 { data_a[ii] = 0xA0u8; ii = ii + 1u64 }
    let mut jj : u64 = 0u64
    while jj < 4u64 { data_b[jj] = 0xB0u8; jj = jj + 1u64 }

    let out_u   : u64 = out   as u64
    let fids_u  : u64 = fids  as u64
    let fdpa_u  : u64 = fdpa  as u64
    let flna_u  : u64 = flna  as u64

    /* === NEGATIVE CASE 1: out_cap = 4, need >= 5 bytes for header. === */
    fids[0u64] = 0x01u8; fids[1u64] = 0u8; fids[2u64] = 0u8; fids[3u64] = 0u8
    _w64(fdpa, 0u64, data_a as u64)
    _w64(fdpa, 8u64, 0u64); _w64(fdpa, 16u64, 0u64); _w64(fdpa, 24u64, 0u64)
    _w32(flna, 0u64, 8u32)
    _w32(flna, 4u64, 0u32); _w32(flna, 8u64, 0u32); _w32(flna, 12u64, 0u32)
    let r1 : u32 = idoc_pack_payload(fids_u, fdpa_u, flna_u, out_u, 4u32)
    if r1 != OVERFLOW_SENTINEL { return 2u64 }

    /* === NEGATIVE CASE 2: out_cap exactly fits facet 0 (5+8=13), facet 1 needs 5+4=9 more.
     *    Provide cap=13+4=17 (not enough for facet 1's 5-byte header + 4 data). === */
    fids[0u64] = 0x01u8; fids[1u64] = 0x02u8; fids[2u64] = 0u8; fids[3u64] = 0u8
    _w64(fdpa, 0u64, data_a as u64)
    _w64(fdpa, 8u64, data_b as u64)
    _w64(fdpa, 16u64, 0u64); _w64(fdpa, 24u64, 0u64)
    _w32(flna, 0u64, 8u32)
    _w32(flna, 4u64, 4u32)
    _w32(flna, 8u64, 0u32); _w32(flna, 12u64, 0u32)
    /* cap=17: fits facet0 (13 bytes) but leaves only 4 bytes for facet1 that needs 9. */
    let r2 : u32 = idoc_pack_payload(fids_u, fdpa_u, flna_u, out_u, 17u32)
    if r2 != OVERFLOW_SENTINEL { return 3u64 }

    /* === NEGATIVE CASE 3: null data pointer for facet 0 with len>0. === */
    fids[0u64] = 0x01u8; fids[1u64] = 0u8; fids[2u64] = 0u8; fids[3u64] = 0u8
    _w64(fdpa, 0u64, 0u64)   /* null pointer */
    _w64(fdpa, 8u64, 0u64); _w64(fdpa, 16u64, 0u64); _w64(fdpa, 24u64, 0u64)
    _w32(flna, 0u64, 8u32)   /* non-zero len -- should fire null-ptr guard */
    _w32(flna, 4u64, 0u32); _w32(flna, 8u64, 0u32); _w32(flna, 12u64, 0u32)
    let r3 : u32 = idoc_pack_payload(fids_u, fdpa_u, flna_u, out_u, 256u32)
    if r3 != OVERFLOW_SENTINEL { return 4u64 }

    /* === NEGATIVE CASE 4: out_cap = 0 with non-zero facet. === */
    fids[0u64] = 0x01u8; fids[1u64] = 0u8; fids[2u64] = 0u8; fids[3u64] = 0u8
    _w64(fdpa, 0u64, data_a as u64)
    _w64(fdpa, 8u64, 0u64); _w64(fdpa, 16u64, 0u64); _w64(fdpa, 24u64, 0u64)
    _w32(flna, 0u64, 1u32)   /* 1-byte facet, needs 6 bytes total */
    _w32(flna, 4u64, 0u32); _w32(flna, 8u64, 0u32); _w32(flna, 12u64, 0u32)
    let r4 : u32 = idoc_pack_payload(fids_u, fdpa_u, flna_u, out_u, 0u32)
    if r4 != OVERFLOW_SENTINEL { return 5u64 }

    /* === NEGATIVE CASE 5: null out_payload_ptr. === */
    _w64(fdpa, 0u64, data_a as u64)
    _w32(flna, 0u64, 8u32)
    let r5 : u32 = idoc_pack_payload(fids_u, fdpa_u, flna_u, 0u64, 256u32)
    if r5 != OVERFLOW_SENTINEL { return 6u64 }

    /* === NEGATIVE CASE 6: null facet_ids_ptr. === */
    let r6 : u32 = idoc_pack_payload(0u64, fdpa_u, flna_u, out_u, 256u32)
    if r6 != OVERFLOW_SENTINEL { return 7u64 }

    /* === POSITIVE CASE 7: exact-fit pack, 2 facets (8+4 data) = 13+9=22 bytes, cap=22. === */
    fids[0u64] = 0x01u8; fids[1u64] = 0x02u8; fids[2u64] = 0u8; fids[3u64] = 0u8
    _w64(fdpa, 0u64, data_a as u64)
    _w64(fdpa, 8u64, data_b as u64)
    _w64(fdpa, 16u64, 0u64); _w64(fdpa, 24u64, 0u64)
    _w32(flna, 0u64, 8u32)
    _w32(flna, 4u64, 4u32)
    _w32(flna, 8u64, 0u32); _w32(flna, 12u64, 0u32)
    let r7 : u32 = idoc_pack_payload(fids_u, fdpa_u, flna_u, out_u, 22u32)
    if r7 != 22u32 { return 8u64 }
    /* Verify first byte is the facet_id 0x01 at offset 0. */
    if out[0u64] != 0x01u8 { return 9u64 }
    /* Verify second facet header's facet_id (0x02) is at offset 13. */
    if out[13u64] != 0x02u8 { return 10u64 }

    /* === POSITIVE CASE 8: single facet, out_cap = 5 + 8 = 13, exact fit. === */
    fids[0u64] = 0x04u8; fids[1u64] = 0u8; fids[2u64] = 0u8; fids[3u64] = 0u8
    _w64(fdpa, 0u64, data_a as u64)
    _w64(fdpa, 8u64, 0u64); _w64(fdpa, 16u64, 0u64); _w64(fdpa, 24u64, 0u64)
    _w32(flna, 0u64, 8u32)
    _w32(flna, 4u64, 0u32); _w32(flna, 8u64, 0u32); _w32(flna, 12u64, 0u32)
    let r8 : u32 = idoc_pack_payload(fids_u, fdpa_u, flna_u, out_u, 13u32)
    if r8 != 13u32 { return 11u64 }

    /* === POSITIVE CASE 9: all-zero lens, any cap -> 0 bytes written. === */
    _w32(flna, 0u64, 0u32); _w32(flna, 4u64, 0u32)
    _w32(flna, 8u64, 0u32); _w32(flna, 12u64, 0u32)
    let r9 : u32 = idoc_pack_payload(fids_u, fdpa_u, flna_u, out_u, 256u32)
    if r9 != 0u32 { return 12u64 }

    free(data_a); free(data_b); free(out)
    free(fids); free(fdpa); free(flna)
    return 99u64
}
